This stems from bfd/elflink.c. This trivial patch fixes (modulo localization strings, which are probably broken) the "invalid DSO for symbol" message:

=====================================8<========================================
--- a/contrib/binutils/bfd/elflink.c
+++ b/contrib/binutils/bfd/elflink.c
@@ -4355,12 +4355,12 @@ elf_link_add_object_symbols (bfd *abfd, struct bfd_link_info *info)
                 Add a DT_NEEDED entry for it.  Issue an error if
                 --no-add-needed is used.  */
              if ((elf_dyn_lib_class (abfd) & DYN_NO_NEEDED) != 0)
                {
                  (*_bfd_error_handler)
-                   (_("%B: invalid DSO for symbol `%s' definition"),
-                   abfd, name);
+                   (_("undefined reference to symbol `%s' (try linking %B)"),
+                   name, abfd);
                  bfd_set_error (bfd_error_bad_value);
                  goto error_free_vers;
                }

              elf_dyn_lib_class (abfd) &= ~DYN_AS_NEEDED;
=====================================8<========================================

But leaves the "//usr/lib/libelf.so.2: could not read symbols: Bad value" message at the bottom. I think this an improvement, but I'll keep poking at the other string...
